import Slideshow from"./slideshow.min.js";document.addEventListener("DOMContentLoaded",()=>{const slideshows=document.querySelectorAll(".slideshow"),slideshowObjs=[],options={threshold:[0,.25,.5,.75,1]},getSlideShowObject=elementNode=>{for(let obj of slideshowObjs)if(obj.wrapperElement.isSameNode(elementNode))return obj;console.log("We were unable to find the corresponding object")},observerCallback=entries=>{entries.forEach(entry=>{let object=getSlideShowObject(entry.target);if(object){if(entry.intersectionRatio>.5)return void object.startSlideshow();object.stopSlideshow()}else console.log("There was no object here!")})},slideshowObserver=new IntersectionObserver(observerCallback,options);slideshows.forEach(slideshow=>{slideshow.classList.contains("permanent")||slideshowObserver.observe(slideshow)}),slideshows.forEach(slideshowElement=>{const slideshowObj=new Slideshow(slideshowElement);slideshowObjs.push(slideshowObj),slideshowElement.classList.contains("permanent")&&slideshowObj.startSlideshow()})});